from contextlib import contextmanager
from typing import Optional

from prefect._internal.concurrency.cancellation import (
    CancelledError,
    cancel_async_after,
    cancel_sync_after,
)


def fail_if_not_timeout_error(timeout_exc_type: type[Exception]) -> None:
    if not issubclass(timeout_exc_type, TimeoutError):
        raise ValueError(
            "The `timeout_exc_type` argument must be a subclass of `TimeoutError`."
        )


@contextmanager
def timeout_async(
    seconds: Optional[float] = None, timeout_exc_type: type[TimeoutError] = TimeoutError
):
    fail_if_not_timeout_error(timeout_exc_type)

    if seconds is None:
        yield
        return

    try:
        with cancel_async_after(timeout=seconds):
            yield
    except CancelledError:
        raise timeout_exc_type(f"Scope timed out after {seconds} second(s).")


@contextmanager
def timeout(
    seconds: Optional[float] = None, timeout_exc_type: type[TimeoutError] = TimeoutError
):
    fail_if_not_timeout_error(timeout_exc_type)

    if seconds is None:
        yield
        return

    try:
        with cancel_sync_after(timeout=seconds):
            yield
    except CancelledError:
        raise timeout_exc_type(f"Scope timed out after {seconds} second(s).")

import orjson
from fastapi import Body, Response
from jinja2.exceptions import TemplateSyntaxError

from prefect.server.utilities.server import PrefectRouter
from prefect.server.utilities.user_templates import (
    TemplateSecurityError,
    validate_user_template,
)

router: PrefectRouter = PrefectRouter(tags=["Automations"])


# deprecated and can be removed after the ui removes its dependency on it
# use /templates/validate instead
@router.post(
    "/automations/templates/validate",
    response_class=Response,
)
@router.post(
    "/templates/validate",
    response_class=Response,
)
def validate_template(template: str = Body(default="")) -> Response:
    try:
        validate_user_template(template)
        return Response(content="", status_code=204)
    except (TemplateSyntaxError, TemplateSecurityError) as e:
        return Response(
            status_code=422,
            media_type="application/json",
            content=orjson.dumps(
                {
                    "error": {
                        "line": e.lineno,
                        "message": e.message,
                        "source": template,
                    },
                }
            ),
        )
